import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getVehicleById, updateVehicle } from "../../api/vehicleApi";

export default function EditVehicle() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState(null);
  const [saving, setSaving] = useState(false);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  useEffect(() => {
    getVehicleById(id)
      .then((res) => setVehicle(res.data))
      .catch(() => {
        alert("Vehicle not found");
        navigate("/vehicles");
      });
  }, [id, navigate]);

  if (!vehicle) return <p style={{ padding: 20 }}>Loading...</p>;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const payload = {
      brand: (vehicle.brand || "").trim(),
      type: vehicle.type,
      year: yearNum,
      price: priceNum,
      status: vehicle.status,
      vehicleNumber: (vehicle.vehicleNumber || "").trim(),
      details: (vehicle.details || "").trim(),
    };

    try {
      setSaving(true);
      await updateVehicle(id, payload);
      alert("Vehicle updated!");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Edit Vehicle</h2>

      <form onSubmit={submit}>
        <label>Brand</label>
        <input
          name="brand"
          value={vehicle.brand || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Vehicle Type</label>
        <select
          name="type"
          value={vehicle.type || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        >
          <option value="">Select Vehicle Type</option>
          {vehicleTypes.map((t) => (
            <option key={t} value={t}>
              {t}
            </option>
          ))}
        </select>

        <label>Year</label>
        <input
          name="year"
          type="number"
          value={vehicle.year ?? ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Price (LKR)</label>
        <input
          name="price"
          type="number"
          value={vehicle.price ?? ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Status</label>
        <select
          name="status"
          value={vehicle.status || "available"}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        >
          {statuses.map((s) => (
            <option key={s} value={s}>
              {s}
            </option>
          ))}
        </select>

        <label>Vehicle Number</label>
        <input
          name="vehicleNumber"
          value={vehicle.vehicleNumber || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        />

        <label>Details</label>
        <textarea
          name="details"
          rows={3}
          value={vehicle.details || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        />

        <button disabled={saving} style={{ padding: "10px 14px" }}>
          {saving ? "Saving..." : "Save Changes"}
        </button>
      </form>
    </div>
  );
}
